// crates/wish/tests/connection_tests.rs
mod common;

#[tokio::test]
async fn test_basic_connection() {
    let server = TestServer::start().await;

    let output = SshClient::new(server.port())
        .with_identity(test_key_path())
        .exec("testuser", "echo hello")
        .output()
        .expect("Failed to execute ssh");

    assert!(output.status.success());
    assert_eq!(String::from_utf8_lossy(&output.stdout).trim(), "hello");

    server.stop().await;
}

#[tokio::test]
async fn test_connection_timeout() {
    let server = TestServer::start_with_config(WishConfig {
        idle_timeout: Duration::from_secs(1),
        ..Default::default()
    }).await;

    // Connect but don't send any data
    let mut stream = TcpStream::connect(format!("127.0.0.1:{}", server.port()))
        .await
        .unwrap();

    // Wait for timeout
    tokio::time::sleep(Duration::from_secs(2)).await;

    // Connection should be closed
    let mut buf = [0u8; 1];
    let result = stream.read(&mut buf).await;
    assert!(result.is_err() || result.unwrap() == 0);

    server.stop().await;
}
