// crates/wish/tests/stress_tests.rs

#[tokio::test]
async fn test_concurrent_connections() {
    let server = TestServer::start().await;

    let mut handles = vec![];

    for i in 0..10 {
        let port = server.port();
        handles.push(tokio::spawn(async move {
            let output = SshClient::new(port)
                .with_identity(test_key_path())
                .exec("testuser", &format!("echo {}", i))
                .output()
                .unwrap();

            output.status.success()
        }));
    }

    for handle in handles {
        assert!(handle.await.unwrap());
    }

    server.stop().await;
}

#[tokio::test]
async fn test_max_sessions_enforcement() {
    let server = TestServer::start_with_config(WishConfig {
        max_sessions: Some(2),
        ..Default::default()
    }).await;

    // Open two connections (keep them alive)
    let _conn1 = open_persistent_connection(server.port()).await;
    let _conn2 = open_persistent_connection(server.port()).await;

    // Third connection should fail
    let output = SshClient::new(server.port())
        .with_identity(test_key_path())
        .exec("testuser", "echo test")
        .output()
        .unwrap();

    assert!(!output.status.success());

    server.stop().await;
