```rust
#[cfg(test)]
mod middleware_tests {
    use super::*;

    struct RejectMiddleware;

    #[async_trait]
    impl Middleware for RejectMiddleware {
        async fn on_connect(&self, _ctx: &mut ConnectionContext) -> MiddlewareResult {
            MiddlewareResult::Reject { reason: "test".into() }
        }
        fn name(&self) -> &'static str { "reject" }
    }

    #[tokio::test]
    async fn test_middleware_chain_continue() {
        let mut chain = MiddlewareChain::new();
        chain.add(LoggingMiddleware::new(log::Level::Debug));

        let mut ctx = ConnectionContext::test();
        let result = chain.run_on_connect(&mut ctx).await;

        assert!(matches!(result, MiddlewareResult::Continue));
    }

    #[tokio::test]
    async fn test_middleware_chain_reject() {
        let mut chain = MiddlewareChain::new();
        chain.add(RejectMiddleware);
        chain.add(LoggingMiddleware::new(log::Level::Debug)); // Should not run

        let mut ctx = ConnectionContext::test();
        let result = chain.run_on_connect(&mut ctx).await;

        assert!(matches!(result, MiddlewareResult::Reject { .. }));
    }

    #[tokio::test]
    async fn test_rate_limit_middleware() {
        let mw = RateLimitMiddleware::new(2, Duration::from_secs(60));

        let mut ctx = ConnectionContext::test();

        // First two should pass
        assert!(matches!(mw.on_connect(&mut ctx).await, MiddlewareResult::Continue));
        assert!(matches!(mw.on_connect(&mut ctx).await, MiddlewareResult::Continue));

        // Third should be rate limited
        assert!(matches!(mw.on_connect(&mut ctx).await, MiddlewareResult::Reject { .. }));
    }
}
