#[cfg(test)]
mod session_tests {
    use super::*;

    #[tokio::test]
    async fn test_session_registration() {
        let registry = SessionRegistry::new(None);

        let info = SessionInfo::test();
        registry.register(info.clone()).await.unwrap();

        assert_eq!(registry.count().await, 1);
        assert!(registry.get(&info.id).await.is_some());
    }

    #[tokio::test]
    async fn test_max_sessions_limit() {
        let registry = SessionRegistry::new(Some(2));

        registry.register(SessionInfo::test_with_id("1")).await.unwrap();
        registry.register(SessionInfo::test_with_id("2")).await.unwrap();

        let result = registry.register(SessionInfo::test_with_id("3")).await;
        assert!(matches!(result, Err(SessionError::MaxSessionsReached)));
    }

    #[tokio::test]
    async fn test_session_unregistration() {
        let registry = SessionRegistry::new(None);

        let info = SessionInfo::test();
        registry.register(info.clone()).await.unwrap();
        registry.unregister(&info.id).await;

        assert_eq!(registry.count().await, 0);
    }

    #[tokio::test]
    async fn test_idle_session_cleanup() {
        let registry = Arc::new(SessionRegistry::new(None));
        let cleaner = SessionCleaner::new(
            registry.clone(),
            Duration::from_millis(100),
            Duration::from_millis(50),
        );

        let info = SessionInfo::test();
        registry.register(info).await.unwrap();

        // Wait for idle timeout
        tokio::time::sleep(Duration::from_millis(200)).await;
        cleaner.cleanup_idle_sessions().await;

        assert_eq!(registry.count().await, 0);
    }
}
