 {"id":"charmed_rust-n85","title":"Implement PTY/Terminal Session Handling","description":"# Implement PTY/Terminal Session Handling

## Objective
Implement PTY allocation and terminal session handling to support interactive terminal sessions over SSH.

## Implementation Details

### PTY Allocation
```rust
use portable_pty::{native_pty_system, PtySize, PtySystem};

pub struct PtySession {
    master: Box<dyn MasterPty + Send>,
    child: Box<dyn Child + Send + Sync>,
    size: PtySize,
}

impl PtySession {
    pub fn new(
        term: &str,
        cols: u16,
        rows: u16,
        command: Option<&str>,
    ) -> Result<Self> {
        log::debug!("Allocating PTY: term={}, size={}x{}", term, cols, rows);

        let pty_system = native_pty_system();
        let size = PtySize {
            rows,
            cols,
            pixel_width: 0,
            pixel_height: 0,
        };

        let pair = pty_system.openpty(size)?;

        let cmd = CommandBuilder::new(command.unwrap_or("/bin/sh"));
        cmd.env("TERM", term);

        let child = pair.slave.spawn_command(cmd)?;

        log::info!("PTY session created with PID {}", child.process_id());

        Ok(Self {
            master: pair.master,
            child,
            size,
        })
    }

    pub fn resize(&mut self, cols: u16, rows: u16) -> Result<()> {
        log::debug!("Resizing PTY to {}x{}", cols, rows);
        self.size = PtySize { rows, cols, ..self.size };
        self.master.resize(self.size)?;
        Ok(())
    }

    pub fn reader(&self) -> Box<dyn Read + Send> {
        self.master.try_clone_reader().unwrap()
    }

    pub fn writer(&self) -> Box<dyn Write + Send> {
        self.master.take_writer().unwrap()
    }
}
```

### Terminal Session State
```rust
pub struct TerminalSession {
    pub pty: PtySession,
    pub term_type: String,
    pub env: HashMap<String, String>,
    pub window_size: WindowSize,
}

#[derive(Clone, Debug)]
pub struct WindowSize {
    pub cols: u16,
    pub rows: u16,
    pub pixel_width: u16,
    pub pixel_height: u16,
}
```

### russh Handler Integration
```rust
impl russh::server::Handler for ConnectionHandler {
    async fn pty_request(
        &mut self,
        channel: ChannelId,
        term: &str,
        col_width: u32,
        row_height: u32,
        pix_width: u32,
        pix_height: u32,
        modes: &[(Pty, u32)],
        session: &mut Session,
    ) -> Result<(), Self::Error> {
        log::info!(
            "PTY request: term={}, size={}x{}", 
            term, col_width, row_height
        );

        let pty_session = PtySession::new(
            term,
            col_width as u16,
            row_height as u16,
            None,
        )?;

        self.channels.insert(channel, ChannelState::Pty(pty_session));
        session.request_success();
        Ok(())
    }

    async fn window_change_request(
        &mut self,
        channel: ChannelId,
        col_width: u32,
        row_height: u32,
        pix_width: u32,
        pix_height: u32,
        session: &mut Session,
    ) -> Result<(), Self::Error> {
        log::debug!("Window change: {}x{}", col_width, row_height);

        if let Some(ChannelState::Pty(pty)) = self.channels.get_mut(&channel) {
            pty.resize(col_width as u16, row_height as u16)?;
        }
        Ok(())
    }

    async fn data(
        &mut self,
        channel: ChannelId,
        data: &[u8],
        session: &mut Session,
    ) -> Result<(), Self::Error> {
        // Forward data to PTY
        if let Some(ChannelState::Pty(pty)) = self.channels.get_mut(&channel) {
            pty.writer().write_all(data)?;
        }
        Ok(())
    }
}
```

### PTY Output Forwarding
```rust
async fn forward_pty_output(
    mut reader: Box<dyn Read + Send>,
    handle: Handle,
    channel: ChannelId,
) {
    let mut buf = [0u8; 4096];
    loop {
        match reader.read(&mut buf) {
            Ok(0) => break, // EOF
            Ok(n) => {
                if handle.data(channel, CryptoVec::from_slice(&buf[..n])).await.is_err() {
                    break;
                }
            }
            Err(e) => {
                log::warn!("PTY read error: {}", e);
                break;
            }
        }
    }
    log::debug!("PTY output forwarding ended for channel {:?}", channel);
}
```

