        prop_oneof![
            Just(MouseButton::Left),
            Just(MouseButton::Middle),
            Just(MouseButton::Right),
            Just(MouseButton::WheelUp),
            Just(MouseButton::WheelDown),
            Just(MouseButton::WheelLeft),
            Just(MouseButton::WheelRight),
