- Place tests in `crates/bubbletea/src/proptest/roundtrip.rs`
- Use `prop_assume!` to skip non-applicable cases
- Some representations may not be exactly equal (non-canonical forms)
- Focus on semantic equality, not byte equality where appropriate
- Add `#[derive(PartialEq, Debug)]` to all relevant types

## Logging Requirements

```rust
use tracing::{debug, trace, warn, instrument};

#[instrument(level = "trace")]
fn verify_roundtrip<T: Parse + Serialize + PartialEq + Debug>(value: &T) -> bool {
    let serialized = value.serialize();
    trace!(serialized = ?serialized, "Serialized value");

    let parsed = T::parse(&serialized);
    match parsed {
        Some((roundtrip, consumed)) => {
            debug!(
                original = ?value,
                roundtrip = ?roundtrip,
                consumed,
                "Roundtrip completed"
            );

            if roundtrip != *value {
                warn!(
                    original = ?value,
                    roundtrip = ?roundtrip,
                    "Roundtrip mismatch!"
                );
                return false;
            }
            true
        }
        None => {
            warn!(serialized = ?serialized, "Failed to parse serialized value");
            false
        }
    }
}
